import * as THREE from 'three';

export function createObject() {
    const group = new THREE.Group();

    const geometry = new THREE.BoxGeometry(1, 1, 1);
    const material = new THREE.MeshStandardMaterial({ color: 0x00ff00 });
    const cube = new THREE.Mesh(geometry, material);
    cube.position.set(0, 0.5, 0);
    group.add(cube);

    const sphereGeometry = new THREE.SphereGeometry(0.5, 32, 32);
    const sphereMaterial = new THREE.MeshStandardMaterial({ color: 0xff0000 });
    const sphere = new THREE.Mesh(sphereGeometry, sphereMaterial);
    sphere.position.set(0, 1.5, 0);
    group.add(sphere);

    return group;
}

import * as THREE from 'three';
import { OBJExporter } from 'three/examples/jsm/exporters/OBJExporter.js';
import { createObject } from './data/object.js';
import fs from 'fs';
import path from 'path';

// 1. Create the object
const object = createObject();

// 2. Apply Blender Z-up space transformation
// Blender is Z-up, Three.js is Y-up.
// To convert from Three.js (Y-up) to Blender (Z-up), we rotate -90 degrees around X axis.
// This makes the original Y axis point towards the new Z axis.
object.rotation.x = -Math.PI / 2;
object.updateMatrixWorld(true);

// 3. Export to OBJ
const exporter = new OBJExporter();
const result = exporter.parse(object);

// 4. Save to file
const outputPath = 'output/object.obj';
const dir = path.dirname(outputPath);
if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
}

fs.writeFileSync(outputPath, result);
console.log(`Successfully exported to ${outputPath}`);
